const agents = $('Fetch Agents').first().json.agents || [];
const decisions = $('Query Decisions').all().map(i => i.json);

// Merge agent info with decision metrics
const ranked = decisions.map((d, idx) => {
  const agent = agents.find(a => a.id === d.agent_id);
  const sharpe = d.pnl_stddev > 0 ? (d.avg_pnl / d.pnl_stddev) : 0;
  const score = (d.total_pnl * 0.4) + (d.win_rate * 0.3) + (sharpe * 100 * 0.3);

  return {
    rank: idx + 1,
    agentId: d.agent_id,
    agentName: agent?.name || d.agent_id,
    strategy: d.strategy,
    totalDecisions: d.total_decisions,
    wins: d.wins,
    losses: d.losses,
    winRate: d.win_rate,
    totalPnl: d.total_pnl,
    avgPnl: d.avg_pnl,
    bestTrade: d.best_trade,
    worstTrade: d.worst_trade,
    sharpe: sharpe.toFixed(3),
    compositeScore: score.toFixed(2)
  };
});

// Sort by composite score
ranked.sort((a, b) => parseFloat(b.compositeScore) - parseFloat(a.compositeScore));
ranked.forEach((r, i) => r.rank = i + 1);

// Build leaderboard
const weekEnd = new Date().toISOString().split('T')[0];
const weekStart = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

let leaderboard = `STRATEGY TOURNAMENT\n`;
leaderboard += `Week: ${weekStart} to ${weekEnd}\n`;
leaderboard += `${'='.repeat(40)}\n\n`;

const medals = ['1st', '2nd', '3rd'];
for (const r of ranked) {
  const medal = r.rank <= 3 ? ` ${medals[r.rank - 1]}` : '';
  leaderboard += `#${r.rank}${medal} ${r.agentName}\n`;
  leaderboard += `  Strategy: ${r.strategy}\n`;
  leaderboard += `  Score: ${r.compositeScore} | PnL: $${r.totalPnl} | Win Rate: ${r.winRate}%\n`;
  leaderboard += `  Trades: ${r.totalDecisions} (W:${r.wins} L:${r.losses}) | Sharpe: ${r.sharpe}\n`;
  leaderboard += `  Best: $${r.bestTrade} | Worst: $${r.worstTrade}\n\n`;
}

if (ranked.length === 0) {
  leaderboard += 'No agent decisions recorded this week.\n';
}

return [{ json: { leaderboard, ranked, chatId: process.env.TELEGRAM_REPORT_CHAT_ID || '' } }];
